import{_ as s}from"./chunks/avatar.DT_Guhso.js";import{_ as e,o as t,c as i,ag as n}from"./chunks/framework.CvgP6Fyv.js";const g=JSON.parse('{"title":"About Me","description":"","frontmatter":{},"headers":[],"relativePath":"en/about.md","filePath":"en/about.md","lastUpdated":null}'),o={name:"en/about.md"};function l(r,a,c,d,h,m){return t(),i("div",null,[...a[0]||(a[0]=[n('<h1 id="about-me" tabindex="-1">About Me <a class="header-anchor" href="#about-me" aria-label="Permalink to &quot;About Me&quot;">​</a></h1><div class="profile-header"><img src="'+s+'" alt="Qi Meng" class="profile-avatar"><div class="profile-info"><h1>Qi Meng</h1><div class="title">Condensed Matter Physics | PhD Student</div><div class="profile-links"><a href="mailto:qimeng0103@gmail.com">📧 Email</a><a href="https://github.com/qimeng0103" target="_blank">🐙 GitHub</a><a href="https://scholar.google.com" target="_blank">🎓 Google Scholar</a></div></div></div><h2 id="🔬-research-interests" tabindex="-1">🔬 Research Interests <a class="header-anchor" href="#🔬-research-interests" aria-label="Permalink to &quot;🔬 Research Interests&quot;">​</a></h2><p>My research focuses on theoretical and computational condensed matter physics, particularly:</p><div class="research-areas"><div class="research-card"><h4>Topological Phases</h4><p>Topological insulators, topological superconductors, Weyl semimetals and other novel quantum materials</p></div><div class="research-card"><h4>Quantum Transport</h4><p>Electronic transport in mesoscopic systems using non-equilibrium Green&#39;s functions and scattering matrix methods</p></div><div class="research-card"><h4>Strongly Correlated Systems</h4><p>Numerical simulations of quantum many-body systems, including DMRG and quantum Monte Carlo methods</p></div><div class="research-card"><h4>Quantum Computing</h4><p>Quantum algorithm design, quantum error correction, and quantum simulation theory</p></div></div><h2 id="💻-technical-tools" tabindex="-1">💻 Technical Tools <a class="header-anchor" href="#💻-technical-tools" aria-label="Permalink to &quot;💻 Technical Tools&quot;">​</a></h2><p>In my daily research, I primarily use the following tools and languages:</p><div class="skills-grid"><div class="skill-item"><span class="skill-icon">🐍</span><span class="skill-name">Python</span></div><div class="skill-item"><span class="skill-icon">🔷</span><span class="skill-name">Julia</span></div><div class="skill-item"><span class="skill-icon">📊</span><span class="skill-name">MATLAB</span></div><div class="skill-item"><span class="skill-icon">⚛️</span><span class="skill-name">Kwant</span></div><div class="skill-item"><span class="skill-icon">🔗</span><span class="skill-name">ITensor</span></div><div class="skill-item"><span class="skill-icon">🌊</span><span class="skill-name">Quantum ESPRESSO</span></div></div><h2 id="📝-about-this-blog" tabindex="-1">📝 About This Blog <a class="header-anchor" href="#📝-about-this-blog" aria-label="Permalink to &quot;📝 About This Blog&quot;">​</a></h2><p>This blog is where I document my learning and research journey. It includes:</p><ul><li><strong>Research Notes</strong> — Understanding and derivations of physics concepts</li><li><strong>Computing Tutorials</strong> — Experience sharing on numerical methods and software</li><li><strong>Paper Reviews</strong> — Reading notes on classic papers and important developments</li><li><strong>Tech Essays</strong> — Programming tips and productivity improvements</li></ul><h2 id="📮-contact" tabindex="-1">📮 Contact <a class="header-anchor" href="#📮-contact" aria-label="Permalink to &quot;📮 Contact&quot;">​</a></h2><p>If you&#39;re interested in my research or have any questions, feel free to reach out:</p><ul><li><strong>Email</strong>: <a href="mailto:qimeng0103@gmail.com" target="_blank" rel="noreferrer">qimeng0103@gmail.com</a></li><li><strong>GitHub</strong>: <a href="https://github.com/qimeng0103" target="_blank" rel="noreferrer">@qimeng0103</a></li></ul><hr><blockquote><p><em>&quot;The first principle is that you must not fool yourself — and you are the easiest person to fool.&quot;</em></p><p>— Richard Feynman</p></blockquote>',16)])])}const v=e(o,[["render",l]]);export{g as __pageData,v as default};
